svg.script:
(function() {

  const SVG_NS = "http://www.w3.org/2000/svg";

  const svg = document.documentElement;

  const path = document.getElementById('trail');

  const pathLength = path.getTotalLength();

  const starGroup = document.getElementById('interactiveStars');



  // Parameters

  const STAR_COUNT = 500;

  const REPEL_STRENGTH = 4.5;

  const RETURN_SPEED = 0.03;

  const MOUSE_REPEL_STRENGTH = 3.0;

  const THRESHOLD = 35;



  // Create stars

  const stars = [];

  for (let i = 0; i < STAR_COUNT; i++) {

    const cx = 30 + Math.random() * 740;

    const cy = 20 + Math.random() * 280;

    const r = 0.8 + Math.random() * 2.2;

    const circle = document.createElementNS(SVG_NS, 'circle');

    circle.setAttribute('cx', cx);

    circle.setAttribute('cy', cy);

    circle.setAttribute('r', r);

    // Color varies: cyan/white/blue

    const col = Math.random();

    circle.setAttribute('fill', col > 0.6 ? '#40c0ff' : (col > 0.3 ? '#a0f0ff' : '#ffffff'));

    circle.setAttribute('filter', 'url(#glow)');

    circle.setAttribute('opacity', 0.6 + Math.random() * 0.4);

    starGroup.appendChild(circle);



    stars.push({

      el: circle,

      origX: cx,

      origY: cy,

      offsetX: 0,

      offsetY: 0

    });

  }



  // Mouse position

  let mouseX = 0, mouseY = 0;

  svg.addEventListener('mousemove', (e) => {

    const rect = svg.getBoundingClientRect();

    mouseX = e.clientX - rect.left;

    mouseY = e.clientY - rect.top;

  });



  // Animation loop

  function animate() {

    const now = performance.now() / 1000;

    const t = (now % 10) / 10; // 0..1

    const ballPos = path.getPointAtLength(t * pathLength);



    stars.forEach(star => {

      const dx = star.el.cx.baseVal.value - ballPos.x;

      const dy = star.el.cy.baseVal.value - ballPos.y;

      const distToBall = Math.sqrt(dx*dx + dy*dy);



      // Repel from ball

      if (distToBall < THRESHOLD) {

        const angle = Math.atan2(dy, dx);

        const force = (THRESHOLD - distToBall) / THRESHOLD * REPEL_STRENGTH;

        star.offsetX += Math.cos(angle) * force;

        star.offsetY += Math.sin(angle) * force;

      }



      // Repel from mouse

      const dxMouse = star.el.cx.baseVal.value - mouseX;

      const dyMouse = star.el.cy.baseVal.value - mouseY;

      const distToMouse = Math.sqrt(dxMouse*dxMouse + dyMouse*dyMouse);

      if (distToMouse < THRESHOLD * 1.5) {

        const angleMouse = Math.atan2(dyMouse, dxMouse);

        const forceMouse = (THRESHOLD*1.5 - distToMouse) / (THRESHOLD*1.5) * MOUSE_REPEL_STRENGTH;

        star.offsetX += Math.cos(angleMouse) * forceMouse;

        star.offsetY += Math.sin(angleMouse) * forceMouse;

      }



      // Return force

      star.offsetX *= (1 - RETURN_SPEED);

      star.offsetY *= (1 - RETURN_SPEED);



      // Apply offset

      star.el.setAttribute('cx', star.origX + star.offsetX);

      star.el.setAttribute('cy', star.origY + star.offsetY);

    });



    requestAnimationFrame(animate);

  }



  requestAnimationFrame(animate);

})();
